#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int X,Y,A,B; scanf("%d %d %d %d", &X, &Y, &A, &B);
        int ans = (X!=A && X!=B) + (Y!=A && Y!=B);
        printf("%d\n", ans);
    }
    return 0;
}

